  1	import * as React from 'react';
  2	import { Grid, GridItem } from '@patternfly/react-core';
  3	import { ChartThemeColor, getTheme } from '@patternfly/react-charts/victory';
  4	
  5	import { AllPromLabelsValues } from 'types/Metrics';
  6	import { ChartModel, DashboardModel } from 'types/Dashboards';
  7	import { getDataSupplier } from 'utils/VictoryChartsUtils';
  8	import { Overlay } from 'types/Overlay';
  9	import { KChart } from './KChart';
 10	import { LineInfo, RawOrBucket } from 'types/VictoryChartInfo';
 11	import { BrushHandlers } from './Container';
 12	import { isArray } from 'lodash';
 13	
 14	export type Props<T extends LineInfo> = {
 15	  colors?: string[];
 16	  dashboard: DashboardModel;
 17	  maximizedChart?: string;
 18	  expandHandler: (expandedChart?: string) => void;
 19	  labelValues: AllPromLabelsValues;
 20	  labelPrettifier?: (key: string, value: string) => string;
 21	  onClick?: (chart: ChartModel, datum: RawOrBucket<T>) => void;
 22	  brushHandlers?: BrushHandlers;
 23	  template?: string;
 24	  dashboardHeight: number;
 25	  showSpans: boolean;
 26	  showTrendlines?: boolean;
 27	  customMetric?: boolean;
 28	  overlay?: Overlay<T>;
 29	  timeWindow?: [Date, Date];
 30	};
 31	
 32	type State = {
 33	  maximizedChart?: string;
 34	};
 35	
 36	export class Dashboard<T extends LineInfo> extends React.Component<Props<T>, State> {
 37	  constructor(props: Props<T>) {
 38	    super(props);
 39	    this.state = {
 40	      maximizedChart: props.maximizedChart
 41	    };
 42	  }
 43	
 44	  render() {
 45	    if (this.state.maximizedChart) {
 46	      const chart = this.props.dashboard.charts.find(c => c.name === this.state.maximizedChart);
 47	      if (chart) {
 48	        return this.renderChart(chart);
 49	      }
 50	    }
 51	
 52	    return (
 53	      <Grid>
 54	        {this.props.dashboard.charts.map(c => {
 55	          return (
 56	            <GridItem span={c.spans} key={c.name}>
 57	              {this.renderChart(c)}
 58	            </GridItem>
 59	          );
 60	        })}
 61	      </Grid>
 62	    );
 63	  }
 64	
 65	  private getChartHeight = (): number => {
 66	    if (this.state.maximizedChart) {
 67	      return this.props.dashboardHeight;
 68	    }
 69	    // Dashboards define the rows that are used
 70	    // Columns are defined using the spans field in the charts definition using a flex strategy
 71	    // When columns span the grid (12 spans) charts move to the next row
 72	    // By default metrics use a 2 row layout
 73	    const rows = this.props.dashboard.rows > 0 ? this.props.dashboard.rows : 2;
 74	    return this.props.dashboardHeight / rows;
 75	  };
 76	
 77	  private renderChart(chart: ChartModel) {
 78	    let colorScale = this.props.colors || getTheme(ChartThemeColor.multi).chart!.colorScale!;
 79	    if (!isArray(colorScale)) {
 80	      colorScale = [colorScale];
 81	    }
 82	    const dataSupplier = getDataSupplier(
 83	      chart,
 84	      { values: this.props.labelValues, prettifier: this.props.labelPrettifier },
 85	      colorScale as string[]
 86	    );
 87	    let onClick: ((datum: RawOrBucket<T>) => void) | undefined = undefined;
 88	    if (this.props.onClick) {
 89	      onClick = (datum: RawOrBucket<T>) => this.props.onClick!(chart, datum);
 90	    }
 91	    return (
 92	      <KChart
 93	        key={chart.name}
 94	        chartHeight={this.getChartHeight()}
 95	        chart={chart}
 96	        showSpans={this.props.showSpans}
 97	        showTrendline={this.props.showTrendlines}
 98	        data={dataSupplier()}
 99	        onToggleMaximized={() => this.onToggleMaximized(chart.name)}
100	        isMaximized={this.state.maximizedChart !== undefined}
101	        overlay={chart.xAxis === 'series' ? undefined : this.props.overlay}
102	        onClick={onClick}
103	        brushHandlers={this.props.brushHandlers}
104	        timeWindow={this.props.timeWindow}
105	      />
106	    );
107	  }
108	
109	  private onToggleMaximized = (chartKey: string): void => {
110	    const maximized = this.state.maximizedChart ? undefined : chartKey;
111	    this.setState({ maximizedChart: maximized });
112	    this.props.expandHandler(maximized);
113	  };
114	}

